#include<bits/stdc++.h>
using namespace std;
 long long gcd(long long a,long long b) {
	if(b)return gcd(b,a%b);
	return a;
}
int main() {
	int a,b,c=0,d=0;
	cin>>a>>b;
	for(int i=1; i<=sqrt(a*b); i++) {
		if((a*b)%i==0 && gcd(i,(a*b)/i)==a) {
			c++;
			if(i*i==a*b)d=1;
		}
	}
	cout<<c*2-d;
	return 0;
}
